447	/// C: `static int os_date(lua_State *L)`
448	///
449	/// Formats the current (or a specified) date/time.
450	///
451	/// * Format starting with `'!'` → use UTC; otherwise local time.
452	/// * Format `"*t"` → push a table with broken-down time fields.
453	/// * Other format → push a formatted string, expanding `%`-specifiers via
454	///   the C-library `strftime`.
455	pub(crate) fn os_date(state: &mut LuaState) -> Result<usize, LuaError> {
456	    // C: size_t slen; const char *s = luaL_optlstring(L, 1, "%c", &slen);
457	    // Clone to Vec<u8> so that `s` does not borrow from `state`.
458	    let format: Vec<u8> = state.opt_arg_lstring(1, Some(b"%c"))?.unwrap_or_default();
459	    let s: &[u8] = &format[..];
460	
461	    // C: time_t t = luaL_opt(L, l_checktime, 2, time(NULL));
462	    // TODO(port): replace stub `0` with `std::time::SystemTime::now()` converted
463	    // to a Unix timestamp (seconds since epoch) in Phase B.
464	    let _t: i64 = if matches!(state.type_at(2), LuaType::None | LuaType::Nil) {
465	        0i64 // Phase A stub for time(NULL)
466	    } else {
467	        check_time(state, 2)?
468	    };
469	
470	    // C: if (*s == '!') { stm = l_gmtime(&t, &tmr); s++; }
471	    // C: else              stm = l_localtime(&t, &tmr);
472	    let (use_utc, s): (bool, &[u8]) = if s.first() == Some(&b'!') {
473	        (true, &s[1..])
474	    } else {
475	        (false, s)
476	    };
477	
478	    // TODO(port): decompose Unix timestamp `_t` into TmFields using `gmtime_r`
479	    // (when use_utc) or `localtime_r`.  Requires `libc` or `chrono`.
480	    // Phase A stub: zero-initialised TmFields.
481	    let _ = use_utc;
482	    let stm = TmFields::default();
483	
484	    // C: if (stm == NULL)
485	    //      return luaL_error(L, "date result cannot be represented in this installation");
486	    // (Phase A stub is always valid — no null check needed.)
487	
488	    if s == b"*t" {
489	        // C: lua_createtable(L, 0, 9);  /* 9 = number of fields */
490	        state.create_table(0, 9)?;
491	        // C: setallfields(L, stm);
492	        set_all_fields(state, &stm)?;
493	    } else {
494	        // C: builds formatted string using luaL_Buffer and per-specifier strftime calls
495	        let mut result: Vec<u8> = Vec::new();
496	        let mut pos: usize = 0;
497	
498	        // C: while (s < se)
499	        while pos < s.len() {
500	            if s[pos] != b'%' {
501	                // C: luaL_addchar(&b, *s++);
502	                result.push(s[pos]);
503	                pos += 1;
504	            } else {
505	                // C: s++;  /* skip '%' */
506	                pos += 1;
507	                if pos >= s.len() {
508	                    break;
509	                }
510	                // C: char cc[4]; cc[0] = '%';
511	                let mut cc = [0u8; 4];
512	                cc[0] = b'%';
513	                let conv = &s[pos..];
514	                // C: s = checkoption(L, s, se - s, cc + 1);
515	                let after = check_strftime_option(state, conv, &mut cc)?;
516	                let oplen = conv.len() - after.len();
517	                pos += oplen;
518	                // C: reslen = strftime(buff, SIZETIMEFMT, cc, stm);
519	                // C: luaL_addsize(&b, reslen);
520	                // The `%%` specifier is data-independent: strftime emits a literal
521	                // `%` byte regardless of the broken-down time, so it is correct to
522	                // handle here even while the rest of strftime is stubbed.
523	                if oplen == 1 && cc[1] == b'%' {
524	                    result.push(b'%');
525	                } else {
526	                    // TODO(port): call platform `strftime` with `cc` as format string
527	                    // and `stm` fields.  Phase A stub emits nothing for each
528	                    // non-`%%` specifier.
529	                    let _ = SIZE_TIME_FMT;
530	                }
531	            }
532	        }
533	        // C: luaL_pushresult(&b);
534	        state.push_string(&result)?;
535	    }
536	    Ok(1)
537	}
