539	/// C: `static int os_time(lua_State *L)`
540	///
541	/// Without arguments: returns the current time as a Unix timestamp (integer).
542	/// With a table argument: interprets the table as broken-down local time,
543	/// normalises the fields via `mktime`, updates the table in place, and returns
544	/// the resulting timestamp.
545	pub(crate) fn os_time(state: &mut LuaState) -> Result<usize, LuaError> {
546	    let t: i64;
547	
548	    // C: if (lua_isnoneornil(L, 1)) { t = time(NULL); }
549	    if matches!(state.type_at(1), LuaType::None | LuaType::Nil) {
550	        // TODO(port): use `std::time::SystemTime::now()` to obtain a Unix timestamp.
551	        t = 0; // Phase A stub
552	    } else {
553	        // C: luaL_checktype(L, 1, LUA_TTABLE);
554	        state.check_arg_type(1, LuaType::Table)?;
555	        // C: lua_settop(L, 1);  /* make sure table is at the top */
556	        // PORT NOTE: must use the public-API `set_top` (relative to the current
557	        // C-frame's `func`), not `LuaState::set_top` which is an inherent that
558	        // sets an absolute stack index and would truncate the entire stack.
559	        lua_vm::api::set_top(state, 1)?;
560	
561	        // C: ts.tm_year = getfield(L, "year",  -1, 1900);
562	        let tm_year  = get_field(state, b"year",  -1, 1900)?;
563	        // C: ts.tm_mon  = getfield(L, "month", -1, 1);
564	        let tm_mon   = get_field(state, b"month", -1, 1)?;
565	        // C: ts.tm_mday = getfield(L, "day",   -1, 0);
566	        let tm_mday  = get_field(state, b"day",   -1, 0)?;
567	        // C: ts.tm_hour = getfield(L, "hour",  12, 0);
568	        let tm_hour  = get_field(state, b"hour",  12, 0)?;
569	        // C: ts.tm_min  = getfield(L, "min",   0,  0);
570	        let tm_min   = get_field(state, b"min",   0,  0)?;
571	        // C: ts.tm_sec  = getfield(L, "sec",   0,  0);
572	        let tm_sec   = get_field(state, b"sec",   0,  0)?;
573	        // C: ts.tm_isdst = getboolfield(L, "isdst");
574	        let tm_isdst = get_bool_field(state, b"isdst")?;
575	
576	        let stm = TmFields {
577	            tm_year,
578	            tm_mon,
579	            tm_mday,
580	            tm_hour,
581	            tm_min,
582	            tm_sec,
583	            tm_isdst,
584	            ..TmFields::default()
585	        };
586	
587	        // C: t = mktime(&ts);
588	        // TODO(port): call `libc::mktime` to normalise stm fields and compute the
589	        // Unix timestamp.  Phase A stub uses 0 and skips normalisation.
590	        t = 0;
591	
592	        // C: setallfields(L, &ts);  /* update fields with normalized values */
593	        // PORT NOTE: In the real implementation, mktime may alter stm (e.g.
594	        // normalise out-of-range values), so we update the table with the
595	        // post-normalisation stm.  Phase A stm is unmodified.
596	        set_all_fields(state, &stm)?;
597	    }
598	
599	    // C: if (t != (time_t)(l_timet)t || t == (time_t)(-1))
600	    //        return luaL_error(L, "time result cannot be represented in this installation");
601	    // PORT NOTE: On 64-bit targets time_t == i64 == lua_Integer so the cast check
602	    // is a no-op.  We only guard against mktime's failure sentinel (−1).
603	    if t == -1 {
604	        return Err(LuaError::runtime(format_args!(
605	            "time result cannot be represented in this installation"
606	        )));
607	    }
608	
609	    // C: l_pushtime(L, t);  where l_timet = lua_Integer → push as integer
610	    state.push(LuaValue::Int(t));
611	    Ok(1)
612	}
