614	/// C: `static int os_difftime(lua_State *L)`
615	///
616	/// Returns the number of seconds between two time values as a float (`t1 − t2`).
617	///
618	/// PORT NOTE: C's `difftime(t1, t2)` returns `t1 − t2` as a `double`.  For
619	/// 64-bit `time_t` this is exact as `f64` up to approximately 2^53 seconds
620	/// (~285 million years), which is sufficient for all practical timestamps.
621	pub(crate) fn os_difftime(state: &mut LuaState) -> Result<usize, LuaError> {
622	    // C: time_t t1 = l_checktime(L, 1);
623	    let t1 = check_time(state, 1)?;
624	    // C: time_t t2 = l_checktime(L, 2);
625	    let t2 = check_time(state, 2)?;
626	    // C: lua_pushnumber(L, (lua_Number)difftime(t1, t2));
627	    state.push(LuaValue::Float((t1 - t2) as f64));
628	    Ok(1)
629	}
