631	/// C: `static int os_setlocale(lua_State *L)`
632	///
633	/// Sets the locale for the given category and pushes the resulting locale name
634	/// as a string, or `nil` on failure.
635	pub(crate) fn os_setlocale(state: &mut LuaState) -> Result<usize, LuaError> {
636	    // C: static const char *const catnames[] = {"all","collate","ctype","monetary","numeric","time",NULL};
637	    const CAT_NAMES: &[&[u8]] = &[
638	        b"all", b"collate", b"ctype", b"monetary", b"numeric", b"time",
639	    ];
640	
641	    // C: const char *l = luaL_optstring(L, 1, NULL);
642	    let _locale: Option<Vec<u8>> = state.opt_arg_lstring(1, None)?;
643	
644	    // C: int op = luaL_checkoption(L, 2, "all", catnames);
645	    let _op: usize = state.check_arg_option(2, Some(b"all"), CAT_NAMES)?;
646	
647	    // C: lua_pushstring(L, setlocale(cat[op], l));
648	    // TODO(port): call `libc::setlocale(cat[op], locale_ptr)` using the `libc` crate.
649	    // The LC_* constants and `setlocale` function are not available in Rust std.
650	    // Phase B should link against libc and implement this properly.
651	    state.push(LuaValue::Nil);
652	    Ok(1)
653	}
