655	/// C: `static int os_exit(lua_State *L)`
656	///
657	/// Exits the host process with the given status code (default `EXIT_SUCCESS = 0`).
658	/// If the second argument is true, also closes the Lua state before exiting.
659	///
660	/// This function is expected to terminate the process and never return normally.
661	pub(crate) fn os_exit(state: &mut LuaState) -> Result<usize, LuaError> {
662	    // C: if (lua_isboolean(L, 1))
663	    //      status = lua_toboolean(L, 1) ? EXIT_SUCCESS : EXIT_FAILURE;
664	    //    else
665	    //      status = (int)luaL_optinteger(L, 1, EXIT_SUCCESS);
666	    let exit_code: i32 = if matches!(state.type_at(1), LuaType::Boolean) {
667	        if state.to_boolean(1) { 0 } else { 1 } // EXIT_SUCCESS = 0, EXIT_FAILURE = 1
668	    } else {
669	        state.opt_arg_integer(1, 0)? as i32
670	    };
671	
672	    // C: if (lua_toboolean(L, 2)) lua_close(L);
673	    if state.to_boolean(2) {
674	        // C: lua_close(L) — tear down the Lua state before exiting
675	        state.close();
676	    }
677	
678	    // C: if (L) exit(status);
679	    // TODO(port): `std::process::exit(exit_code)` is banned in lua-stdlib per
680	    // PORTING.md.  The correct design is a `LuaError::Exit(i32)` variant (not yet
681	    // defined in lua-types) that `lua-cli`'s main loop intercepts and converts to
682	    // `std::process::exit`.  For Phase A, propagate as a status-coded error so the
683	    // call stack unwinds — the exit code is passed via `with_status` as a
684	    // placeholder (semantic mismatch intentional; flagged for Phase B).
685	    let _ = exit_code;
686	    Err(LuaError::with_status(lua_types::LuaStatus::Ok))
687	}
