64	/// as `"year"`, `"month"`) inside error messages, without allocating a `String`.
65	struct ByteDisplay<'a>(&'a [u8]);
66	
67	impl std::fmt::Display for ByteDisplay<'_> {
68	    fn fmt(&self, f: &mut std::fmt::Formatter<'_>) -> std::fmt::Result {
69	        for &b in self.0 {
70	            write!(f, "{}", b as char)?;
71	        }
72	        Ok(())
