78	/// C: `static void setfield(lua_State *L, const char *key, int value, int delta)`
79	///
80	/// Pushes `(value as i64) + (delta as i64)` as a Lua integer, then stores it
81	/// in the table currently on top of the stack at field `key`.
82	fn set_field(state: &mut LuaState, key: &[u8], value: i32, delta: i32) -> Result<(), LuaError> {
83	    // C: lua_pushinteger(L, (lua_Integer)value + delta);
84	    state.push(LuaValue::Int((value as i64) + (delta as i64)));
85	    // C: lua_setfield(L, -2, key);
86	    state.set_field(-2, key)?;
87	    Ok(())
88	}
