90	/// C: `static void setboolfield(lua_State *L, const char *key, int value)`
91	///
92	/// Stores a boolean at field `key` in the table on top of the stack.
93	/// A negative `value` means "undefined" — the field is silently skipped.
94	fn set_bool_field(state: &mut LuaState, key: &[u8], value: i32) -> Result<(), LuaError> {
95	    // C: if (value < 0) return;  /* undefined? */
96	    if value < 0 {
97	        return Ok(());
98	    }
99	    // C: lua_pushboolean(L, value);
100	    state.push(LuaValue::Bool(value != 0));
101	    // C: lua_setfield(L, -2, key);
102	    state.set_field(-2, key)?;
103	    Ok(())
