117	    set_field(state, b"day",   stm.tm_mday, 0)?;
118	    // C: setfield(L, "hour",  stm->tm_hour, 0);
119	    set_field(state, b"hour",  stm.tm_hour, 0)?;
120	    // C: setfield(L, "min",   stm->tm_min,  0);
121	    set_field(state, b"min",   stm.tm_min,  0)?;
122	    // C: setfield(L, "sec",   stm->tm_sec,  0);
123	    set_field(state, b"sec",   stm.tm_sec,  0)?;
124	    // C: setfield(L, "yday",  stm->tm_yday, 1);
125	    set_field(state, b"yday",  stm.tm_yday, 1)?;
126	    // C: setfield(L, "wday",  stm->tm_wday, 1);
127	    set_field(state, b"wday",  stm.tm_wday, 1)?;
