134	///
135	/// Reads a boolean field from the table on top of the stack.
136	/// Returns `-1` when the field is absent (nil), or `0` / `1` for false / true.
137	fn get_bool_field(state: &mut LuaState, key: &[u8]) -> Result<i32, LuaError> {
138	    // C: res = (lua_getfield(L, -1, key) == LUA_TNIL) ? -1 : lua_toboolean(L, -1);
139	    let ty = state.get_field(-1, key)?;
140	    let res = if matches!(ty, LuaType::Nil) {
141	        -1i32
142	    } else {
143	        // C: lua_toboolean(L, -1)
144	        state.to_boolean(-1) as i32
145	    };
146	    // C: lua_pop(L, 1);
147	    state.pop_n(1);
148	    Ok(res)
149	}
