151	/// C: `static int getfield(lua_State *L, const char *key, int d, int delta)`
152	///
153	/// Reads an integer field from the table on top of the stack.
154	///
155	/// * `d` — default when the field is absent; pass `d < 0` to make absence an
156	///   error.
157	/// * `delta` — subtracted from the read value to convert from Lua's offset
158	///   representation back to C-library conventions (e.g. month−1, year−1900).
159	///
160	/// PORT NOTE: Stack cleanup on error paths (pop before returning Err) is added
161	/// vs. the C version where `luaL_error` never returns (longjmp).
162	fn get_field(
163	    state: &mut LuaState,
164	    key: &[u8],
165	    d: i32,
166	    delta: i32,
167	) -> Result<i32, LuaError> {
168	    // C: int t = lua_getfield(L, -1, key);
169	    let ty = state.get_field(-1, key)?;
170	    // C: lua_Integer res = lua_tointegerx(L, -1, &isnum);
171	    let maybe_int = state.to_integer_x(-1);
172	    let res: i32 = match maybe_int {
173	        Some(res) => {
174	            // C: if (!(res >= 0 ? res - delta <= INT_MAX : INT_MIN + delta <= res))
175	            //        return luaL_error(L, "field '%s' is out-of-bound", key);
176	            let in_bounds = if res >= 0 {
177	                res.saturating_sub(delta as i64) <= (i32::MAX as i64)
178	            } else {
179	                (i32::MIN as i64).saturating_add(delta as i64) <= res
180	            };
181	            if !in_bounds {
182	                state.pop_n(1);
183	                return Err(LuaError::runtime(format_args!(
184	                    "field '{}' is out-of-bound",
185	                    ByteDisplay(key),
186	                )));
187	            }
188	            // C: res -= delta;
189	            (res - delta as i64) as i32
190	        }
191	        None => {
192	            // C: if (l_unlikely(t != LUA_TNIL))
193	            if !matches!(ty, LuaType::Nil) {
194	                state.pop_n(1);
195	                // C: return luaL_error(L, "field '%s' is not an integer", key);
196	                return Err(LuaError::runtime(format_args!(
197	                    "field '{}' is not an integer",
198	                    ByteDisplay(key),
199	                )));
200	            } else if d < 0 {
201	                state.pop_n(1);
202	                // C: return luaL_error(L, "field '%s' missing in date table", key);
203	                return Err(LuaError::runtime(format_args!(
204	                    "field '{}' missing in date table",
205	                    ByteDisplay(key),
206	                )));
207	            }
208	            d
209	        }
210	    };
211	    // C: lua_pop(L, 1);
212	    state.pop_n(1);
213	    Ok(res)
214	}
